// ═══ JWT AUTH INTERCEPTOR ═══
// Automatically adds Authorization header to brand API calls
const _originalFetch = window.fetch;
window.fetch = function(url, options = {}) {
  if (typeof url === 'string' && (url.startsWith('/api/brand/') || url.startsWith('/api/launch') || url.startsWith('/api/billing/') || url.startsWith('/api/ai/'))) {
    const token = localStorage.getItem('creatorship_brand_token');
    if (token) {
      const headers = options.headers instanceof Headers ? Object.fromEntries(options.headers.entries()) : { ...(options.headers || {}) };
      headers['Authorization'] = 'Bearer ' + token;
      options = { ...options, headers };
    }
  }
  return _originalFetch.call(this, url, options).then(response => {
    // Auto-logout on 401 (expired/invalid token) for brand API calls
    if (response.status === 401 && typeof url === 'string' && url.startsWith('/api/brand/') && !url.includes('/api/brand/login') && !url.includes('/api/brand/signup')) {
      const clone = response.clone();
      clone.json().then(d => {
        if (d.code === 'TOKEN_EXPIRED' || d.code === 'INVALID_TOKEN' || d.code === 'NO_TOKEN') {
          localStorage.removeItem('creatorship_brand');
          localStorage.removeItem('creatorship_brand_token');
          window.location.href = '/brand';
        }
      }).catch(() => {});
    }
    return response;
  });
};

function getSupabase() {
  const url = typeof import.meta !== 'undefined' && import.meta.env && import.meta.env.VITE_SUPABASE_URL;
  const key = typeof import.meta !== 'undefined' && import.meta.env && import.meta.env.VITE_SUPABASE_ANON_KEY;
  if (url && key) return createClient(url, key);
  return null;
}

async function resolveRoleByEmail(email) {
  if (!email) return 'brand';
  try {
    const r = await fetch('/api/brand/me?email=' + encodeURIComponent(email));
    const d = await r.json().catch(() => ({}));
    if (d && !d.error) return 'brand';
  } catch (_) {}
  return 'creator';
}

// ── Role-based access control (frontend helpers for UX) ──
const ROLE_LEVEL = { owner: 4, admin: 3, editor: 2, viewer: 1 };

function base64UrlDecode(input) {
  const str = String(input || '')
    .replace(/-/g, '+')
    .replace(/_/g, '/');
  const pad = str.length % 4;
  const padded = pad ? str + '='.repeat(4 - pad) : str;
  return atob(padded);
}

function getBrandUserRole() {
  if (typeof window === 'undefined') return 'owner';
  const token = localStorage.getItem('creatorship_brand_token');
  if (!token) return 'owner';
  try {
    const payload = JSON.parse(base64UrlDecode(token.split('.')[1]));
    return payload?.role || 'owner';
  } catch (_) {
    return 'owner';
  }
}

function canDo(userRole, action) {
  const roleActions = {
    view: 'viewer',
    edit_campaigns: 'editor',
    launch: 'editor',
    toggle_campaign: 'editor',
    run_deep_dive: 'admin',
    run_cai: 'admin',
    upload_content: 'editor',
    edit_settings: 'admin',
    manage_team: 'admin',
    manage_billing: 'admin',
    billing: 'admin',
    connect_integrations: 'admin',
    delete_brand: 'owner',
    delete_account: 'owner',
  };
  const required = roleActions[action] || 'owner';
  return (ROLE_LEVEL[userRole] || 0) >= (ROLE_LEVEL[required] || 99);
}

class ErrorBoundary extends Component {
  constructor(props) { super(props); this.state = { hasError: false, error: null }; }
  static getDerivedStateFromError(error) { return { hasError: true, error }; }
  componentDidCatch(error, info) { console.error('[ErrorBoundary]', error, info); }
  render() {
    if (this.state.hasError) {
      return (
        <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#030711', color: '#fff', fontFamily: 'inherit' }}>
          <div style={{ textAlign: 'center', maxWidth: 400, padding: 32 }}>
            <div style={{ fontSize: 32, marginBottom: 16 }}>⚠️</div>
            <h2 style={{ fontSize: 20, fontWeight: 800, marginBottom: 8 }}>Something went wrong</h2>
            <p style={{ fontSize: 14, color: '#8b95a5', marginBottom: 4 }}>{this.state.error?.message || 'An unexpected error occurred'}</p>
            <p style={{ fontSize: 13, color: '#5a6270', marginBottom: 20 }}>Try refreshing or going back.</p>
            <button onClick={() => { this.setState({ hasError: false, error: null }); window.location.reload(); }} style={{ padding: '12px 28px', background: '#0668E1', border: 'none', borderRadius: 8, color: '#fff', fontSize: 14, fontWeight: 700, cursor: 'pointer' }}>Try again</button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

