// ═══ TOAST NOTIFICATION SYSTEM ═══
const ToastContext = createContext();
function useToast() { return useContext(ToastContext); }

function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([]);
  const addToast = useCallback((msg, type = 'success', duration = 4000) => {
    const id = Date.now() + Math.random();
    setToasts(t => [...t, { id, msg, type }]);
    if (type !== 'error') setTimeout(() => setToasts(t => t.filter(x => x.id !== id)), duration);
  }, []);
  const removeToast = useCallback((id) => setToasts(t => t.filter(x => x.id !== id)), []);
  const toast = useMemo(() => ({
    success: (msg) => addToast(msg, 'success'),
    error: (msg) => addToast(msg, 'error', 8000),
    warn: (msg) => addToast(msg, 'warning', 5000),
    info: (msg) => addToast(msg, 'info'),
  }), [addToast]);
  return (
    <ToastContext.Provider value={toast}>
      {children}
      <div style={{ position: 'fixed', top: 16, right: 16, zIndex: 99999, display: 'flex', flexDirection: 'column', gap: 8, maxWidth: 380 }}>
        {toasts.map(t => {
          const colors = { success: { bg: '#065f46', border: '#34d399', icon: '✓' }, error: { bg: '#7f1d1d', border: '#ef4444', icon: '✕' }, warning: { bg: '#78350f', border: '#f59e0b', icon: '⚠' }, info: { bg: '#1e1b4b', border: '#9b6dff', icon: 'ℹ' } };
          const c = colors[t.type] || colors.info;
          return (
            <div key={t.id} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', background: c.bg, border: '1px solid ' + c.border, borderRadius: 10, color: '#fff', fontSize: 13, fontWeight: 500, animation: 'slideInRight .3s ease', boxShadow: '0 8px 24px rgba(0,0,0,.3)', lineHeight: 1.4 }}>
              <span style={{ fontSize: 16, flexShrink: 0 }}>{c.icon}</span>
              <span style={{ flex: 1 }}>{t.msg}</span>
              <button onClick={() => removeToast(t.id)} style={{ background: 'none', border: 'none', color: 'rgba(255,255,255,.6)', cursor: 'pointer', fontSize: 16, padding: 0, lineHeight: 1, flexShrink: 0 }}>×</button>
            </div>
          );
        })}
      </div>
      <style>{`@keyframes slideInRight { from { transform: translateX(100%); opacity: 0; } to { transform: translateX(0); opacity: 1; } }`}</style>
    </ToastContext.Provider>
  );
}

// ═══ CONFIRMATION MODAL ═══
let _confirmResolve = null;
let _setConfirmState = null;

function ConfirmModal() {
  const [state, setState] = useState(null);
  _setConfirmState = setState;
  if (!state) return null;
  const { title, message, confirmText, cancelText, destructive } = state;
  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.65)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 99998, padding: 24 }} onClick={() => { _confirmResolve?.(false); setState(null); }}>
      <div onClick={e => e.stopPropagation()} style={{ background: 'var(--cs-card, #1a1a2e)', border: '1px solid var(--cs-a10, #333)', borderRadius: 16, maxWidth: 420, width: '100%', padding: '24px', boxShadow: '0 24px 48px rgba(0,0,0,.4)' }}>
        <div style={{ fontSize: 18, fontWeight: 800, color: 'var(--cs-t1, #fff)', marginBottom: 8 }}>{title || 'Confirm'}</div>
        <div style={{ fontSize: 14, color: 'var(--cs-t3, #aaa)', lineHeight: 1.6, marginBottom: 20, whiteSpace: 'pre-line' }} dangerouslySetInnerHTML={{ __html: (message || '').replace(/\*\*(.+?)\*\*/g, '<strong style="color:var(--cs-t1,#fff)">$1</strong>') }} />
        <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}>
          <button onClick={() => { _confirmResolve?.(false); setState(null); }} style={{ padding: '10px 20px', background: 'var(--cs-a06, #333)', border: '1px solid var(--cs-a08, #444)', borderRadius: 10, color: 'var(--cs-t3, #aaa)', fontSize: 14, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit' }}>{cancelText || 'Cancel'}</button>
          <button onClick={() => { _confirmResolve?.(true); setState(null); }} style={{ padding: '10px 20px', background: destructive ? '#ef4444' : 'linear-gradient(135deg, #9b6dff, #0668E1)', border: 'none', borderRadius: 10, color: '#fff', fontSize: 14, fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit' }}>{confirmText || 'Confirm'}</button>
        </div>
      </div>
    </div>
  );
}

function showConfirm({ title, message, confirmText, cancelText, destructive }) {
  return new Promise(resolve => {
    _confirmResolve = resolve;
    _setConfirmState?.({ title, message, confirmText, cancelText, destructive });
  });
}

