// CAi Ad Performance Prediction — estimates how well a TikTok video would perform as a Meta ad
function caiAdPredict(v) {
  const views = v.views || 0;
  const likes = v.likes || 0;
  const comments = v.comments || 0;
  const shares = v.shares || 0;
  const saves = v.saves || 0;
  const engRate = views > 0 ? (likes + comments + shares) / views * 100 : 0;
  const shareRate = views > 0 ? shares / views * 100 : 0;
  const saveRate = views > 0 ? saves / views * 100 : 0;

  // CAi Ad Score (0-100) — weighted composite
  const engScore = Math.min(engRate * 8, 35);
  const viralScore = views > 0 ? Math.min(Math.log10(views) * 4, 25) : 0;
  const shareScore = Math.min(shareRate * 50, 20);
  const saveScore = Math.min(saveRate * 80, 15);
  const commentScore = views > 0 ? Math.min((comments / views) * 500, 5) : 0;
  const adScore = Math.round(Math.min(engScore + viralScore + shareScore + saveScore + commentScore, 100));

  // Estimated ROAS — based on engagement quality
  let estRoas = 1.8;
  estRoas += Math.min(engRate * 0.25, 1.2);
  estRoas += Math.min(shareRate * 5, 0.8);
  if (views > 10000000) estRoas += 0.6;
  else if (views > 1000000) estRoas += 0.3;
  else if (views > 100000) estRoas += 0.1;
  if (saveRate > 0.5) estRoas += 0.4;
  estRoas = Math.round(Math.min(estRoas, 6.5) * 10) / 10;

  // Revenue estimates at $5K/month ad spend
  const monthlySpend = 5000;
  const revenue = Math.round(monthlySpend * estRoas);
  const platformFee = Math.round(monthlySpend * 0.04);
  const commission = Math.round(revenue * 0.10);
  const profit = revenue - monthlySpend - platformFee - commission;

  // Suggested daily budget based on views/engagement
  const dailyBudget = views >= 10000000 ? Math.round(80 + adScore * 0.7) : views >= 1000000 ? Math.round(30 + adScore * 0.3) : Math.round(15 + adScore * 0.25);
  // CPA estimate
  const avgPrice = 30;
  const estCpa = estRoas > 0 ? Math.round(avgPrice / estRoas * 10) / 10 : null;

  return { adScore, estRoas, revenue, profit, monthlySpend, engRate: Math.round(engRate * 100) / 100, dailyBudget, estCpa };
}

