            <div style={{padding:"12px",background:"var(--cs-a04)",borderRadius:10,textAlign:"center"}}><div className="mono" style={{fontSize:15,fontWeight:700,color:C.green}}>{d.perSale||"—"}</div><div style={{fontSize: 11,color:C.dim,textTransform:"uppercase",marginTop:2}}>Per Sale</div></div>
