                    <span key={i} style={{ fontSize: 11, padding: '4px 10px', borderRadius: 20, background: 'rgba(155,109,255,.06)', border: '1px solid rgba(155,109,255,.1)', color: 'var(--cs-t3)' }}>{d}</span>
