                  <span style={{ fontSize: 11, padding: '3px 8px', borderRadius: 4, background: 'rgba(6,104,225,.1)', border: '1px solid rgba(6,104,225,.2)', color: '#0668E1', fontWeight: 800, fontFamily: 'var(--font-mono)' }}>3</span>
